oxy_webhelp_navlinks = {"archiving_data_center_workloads-d27243e5763":{"topics":[{"title":"Archival data encryption","shortdesc":"<p class=\"shortdesc\">The Rubrik cluster supports and enforces client-side data encryption for all archival         storage types.<\/p>","href":"archival\/arch_archival_data_encryption.html","attributes":{"data-id":"arch_archival_data_encryption"},"menu":{"hasChildren":false},"tocID":"arch_archival_data_encryption-d27243e5777","topics":[]},{"title":"Archival bucket exclusivity","shortdesc":"<p class=\"shortdesc\">Only one Rubrik cluster can archive data to a specific archival bucket.<\/p>","href":"common\/archival_bucket_exclusivity.html","attributes":{"data-id":"archival_bucket_exclusivity"},"menu":{"hasChildren":false},"tocID":"archival_bucket_exclusivity-d27243e5788","topics":[]},{"title":"Archival process","shortdesc":"<p class=\"shortdesc\">The process of archiving data follows a standard sequence of tasks. During the         archival process, the Rubrik cluster determines whether to upload an incremental or full         copy of the archival snapshot.<\/p>","href":"archival\/arch_archival_process.html","attributes":{"data-id":"arch_archival_process"},"menu":{"hasChildren":false},"tocID":"arch_archival_process-d27243e5799","next":"arch_archival_process-d27243e5799"},{"title":"Archival locations","shortdesc":"<p class=\"shortdesc\">The Archival locations page provides summary information about existing archival         locations.<\/p>","href":"archival\/arch_archival_locations_page.html","attributes":{"data-id":"arch_archival_locations_page"},"menu":{"hasChildren":false},"tocID":"arch_archival_locations_page-d27243e5821","next":"arch_archival_locations_page-d27243e5821"},{"title":"Archiving data center workloads in Azure","shortdesc":"<p class=\"shortdesc\">Archiving data center workloads from a Rubrik cluster to Microsoft Azure requires         specific configuration on Azure and <span class=\"ph\">RSC<\/span> before archiving can         begin.<\/p>","href":"archival\/archiving_dc_workloads_azure.html","attributes":{"data-id":"archiving_dc_workloads_azure"},"menu":{"hasChildren":false},"tocID":"archiving_dc_workloads_azure-d27243e6133","next":"archiving_dc_workloads_azure-d27243e6133"},{"title":"Amazon S3 archival locations","shortdesc":"<p class=\"shortdesc\">Rubrik CDM supports Amazon S3 as an archival location. You can use <span class=\"ph\">RSC<\/span> to create an Amazon S3 archival location.<\/p>","href":"archival\/arch_amazon_s3.html","attributes":{"data-id":"arch_amazon_s3"},"menu":{"hasChildren":false},"tocID":"arch_amazon_s3-d27243e6445","next":"arch_amazon_s3-d27243e6445"},{"title":"Verifying cloud compute connectivity","shortdesc":"<p class=\"shortdesc\">Use the cloud compute connectivity check in <span class=\"ph\">RSC<\/span> to verify         connectivity between cloud compute instances, a Rubrik cluster, and AWS or Azure cloud         storage services using Archival Consolidation.<\/p>","href":"archival\/verifying_cloud_compute_connectivity.html","attributes":{"data-id":"verifying_cloud_compute_connectivity"},"menu":{"hasChildren":false},"tocID":"verifying_cloud_compute_connectivity-d27243e6717","topics":[]},{"title":"Instant tiering of snapshots","shortdesc":"<p class=\"shortdesc\">The instant tiering feature archives data immediately to the specified cold storage         tier in the cloud. This approach is ideal for optimizing storage costs when data restoration         is a rare requirement.<\/p>","href":"archival\/arch_instant_tiering_snapshots.html","attributes":{"data-id":"arch_instant_tiering_snapshots"},"menu":{"hasChildren":false},"tocID":"arch_instant_tiering_snapshots-d27243e6731","next":"arch_instant_tiering_snapshots-d27243e6731"},{"title":"Google Cloud Platform archival locations","shortdesc":"<p class=\"shortdesc\">Rubrik CDM supports Google Cloud Platform as an archival location.<\/p>","href":"archival\/arch_gcp.html","attributes":{"data-id":"arch_google_cloud"},"menu":{"hasChildren":false},"tocID":"arch_google_cloud-d27243e6753","next":"arch_google_cloud-d27243e6753"},{"title":"Amazon S3 compatible archival locations","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> supports archival locations that support standard S3         APIs.<\/p>","href":"archival\/amazon_s3_comp_archival_loc.html","attributes":{"data-id":"amazon_s3_comp_archival_loc"},"menu":{"hasChildren":false},"tocID":"amazon_s3_comp_archival_loc-d27243e6797","next":"amazon_s3_comp_archival_loc-d27243e6797"},{"title":"IBM COS archival locations","shortdesc":"<p class=\"shortdesc\">         <span class=\"ph\">RSC<\/span> supports IBM Cloud Object Storage as an archival location         for which you can configure the immutability.<\/p>","href":"archival\/ibm_cos_archival_locations.html","attributes":{"data-id":"ibm_cos_archival_locations"},"menu":{"hasChildren":false},"tocID":"ibm_cos_archival_locations-d27243e6846","next":"ibm_cos_archival_locations-d27243e6846"},{"title":"Dell ECS archival location","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> supports Dell ECS Object Store as an archival         location to configure immutability for archiving encrypted data.<\/p>","href":"archival\/dell_ecs_arch_loc.html","attributes":{"data-id":"dell_ecs_arch_loc"},"menu":{"hasChildren":false},"tocID":"dell_ecs_arch_loc-d27243e6893","next":"dell_ecs_arch_loc-d27243e6893"},{"title":"NetApp StorageGRID archival locations","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> supports using NetApp StorageGRID as archival         locations for archiving encrypted data. For data stored in NetApp StorageGRID archival         locations, Rubrik provides bucket-level immutability.<\/p>","href":"archival\/netapp_sg_arch_loc.html","attributes":{"data-id":"netapp_sg_arch_loc"},"menu":{"hasChildren":false},"tocID":"netapp_sg_arch_loc-d27243e6939","next":"netapp_sg_arch_loc-d27243e6939"},{"title":"NFS archival locations","shortdesc":"<p class=\"shortdesc\">An NFS archival location is storage on an NFS server where you can archive snapshots         from your Rubrik cluster. You must identify a specific location on the NFS server to serve         as the archival location.<\/p>","href":"archival\/arch_nfs.html","attributes":{"data-id":"arch_nfs_archival_locations"},"menu":{"hasChildren":false},"tocID":"arch_nfs_archival_locations-d27243e6974","next":"arch_nfs_archival_locations-d27243e6974"},{"title":"QStar tape archive","shortdesc":"<p class=\"shortdesc\">QStar tape archive enables Rubrik cluster to store data on tape for long-term retention     and regulatory compliance using QStar Archive Manager on Windows server.<\/p>","href":"archival\/archiving_qstar_tape_archive.html","attributes":{"data-id":"archiving_qstar_tape_archive"},"menu":{"hasChildren":false},"tocID":"archiving_qstar_tape_archive-d27243e7018","topics":[]},{"title":"Disaster recovery using an archival location","shortdesc":"<p class=\"shortdesc\">Rubrik CDM supports recovering data from an existing archival location using a Rubrik     cluster that is different from the Rubrik cluster that archives data to the     location.<\/p>","href":"archival\/arch_disaster_recovery_using_arch_loc.html","attributes":{"data-id":"arch_disaster_recovery_using_arch_loc"},"menu":{"hasChildren":false},"tocID":"arch_disaster_recovery_using_arch_loc-d27243e7029","next":"arch_disaster_recovery_using_arch_loc-d27243e7029"},{"title":"Archival network throttling","shortdesc":"<p class=\"shortdesc\">Archival network throttling is a feature by which you can limit the bandwidth of the         network used by a Rubrik cluster to archive data so that more bandwidth is available for         other backup and recovery operations on the Rubrik cluster.<\/p>","href":"archival\/arch_nw_throttling.html","attributes":{"data-id":"arch_nw_throttling"},"menu":{"hasChildren":false},"tocID":"arch_nw_throttling-d27243e7128","next":"arch_nw_throttling-d27243e7128"}]}};